INSERT INTO `tbl_articles` (`id`, `parent_id`, `slug`, `title`, `sub_title`, `content`, `linktype`, `linksrc`, `status`, `meta_title`, `meta_keywords`, `meta_description`, `type`, `added_date`, `modified_date`, `sortorder`, `homepage`, `image`, `date`, `category`, `upcoming`, `brief`) VALUES
(29,	0,	'home',	'Homepage ',	'article',	'<section class=\"pt80\" data-bgcolor=\"#3b1512\" id=\"section-intro\">\r\n	<div class=\"container\">\r\n		<div class=\"row align-items-center\">\r\n			<!-- <div class=\"col-lg-3 col-6\">\r\n                    <div class=\"spacer-double sm-hide\"></div>\r\n                    <img src=\"template/web/assets/images/misc/1.jpg\" alt=\"\" class=\"img-responsive wow fadeInUp\" data-wow-duration=\"1s\">\r\n                </div>\r\n\r\n                <div class=\"col-lg-3 col-6\">\r\n                    <img src=\"template/web/assets/images/misc/2.jpg\" alt=\"\" class=\"img-responsive wow fadeInUp\" data-wow-duration=\"1.5s\">\r\n                </div> -->\r\n			<div class=\"fadeIn\">\r\n				<div class=\"padding20\">\r\n					<h5>\r\n						About Us</h5>\r\n					<h2 class=\"title mb10\">\r\n						Experience the Art of<br />\r\n						True Hospitality</h2>\r\n					<p>\r\n						Ma Hospitality is a premier hospitality brand committed to delivering exceptional experiences that blend comfort, culture, and care. Rooted in the essence of &ldquo;Ma,&rdquo; symbolizing warmth, nurturing, and trust, we aim to create spaces where guests feel not just welcomed, but truly at home.</p>\r\n					<p>\r\n						At Ma Hospitality, we believe hospitality is an art &mdash; an art of anticipating needs, creating memorable moments, and fostering genuine connections. We are passionate about sustainability and social responsibility, supporting local communities, sourcing ethically, and embracing eco-friendly practices wherever possible.</p>\r\n					<!-- <a href=\"#\" class=\"btn-line\"><span>Book Now</span>s</a> --></div>\r\n			</div>\r\n			<div class=\"clearfix\">\r\n				&nbsp;</div>\r\n		</div>\r\n	</div>\r\n</section>\r\n<div class=\"white-border-bottom opacity-50\"></div>\r\n<section class=\"pt80 pb80\" data-bgcolor=\"#3b1512\" id=\"section-ceo-message\" style=\"margin-bottom: 70px;\">\r\n	<div class=\"container\">\r\n		<div class=\"row align-items-center\">\r\n			<div class=\"col-lg-4 text-center mb-4 mb-lg-0\">\r\n				<img alt=\"CEO Photo\" class=\"img-fluid shadow wow fadeInUp\" data-wow-duration=\"1s\" height=\"300\" src=\"template/web/assets/images/ceo.jpg\" width=\"300\" />\r\n				<h4 class=\"mt-3 mb-0\">\r\n					Devendra Giri</h4>\r\n				<span class=\"text-white\">CEO</span></div>\r\n			<div class=\"col-lg-8\">\r\n				<div class=\"padding20 wow fadeIn\" data-wow-duration=\"1.5s\">\r\n					<h5 class=\"mb-3\">\r\n						Message from the CEO</h5>\r\n					<p>\r\n						MA HOSPITALTIY NEPAL has established a very positive impact across our diverse business ventures. Our reputation has influenced various aspects of our company. As a rapidly growing corporate organization, MA HOSPITALITY NEPAL provides a wide range of services in Tourism, Trade, and Social Services through various specialized companies tailored to our customers&#39; requirements. Today, each company within our group is growing steadily and becoming a market leader in its respective field.</p>\r\n					<p>\r\n						MA HOSPITALITY NEPAL is not only involved in the Tourism and Hospitality sector but is also committed to improving children&#39;s lives and futures in our community. We achieve this through our sponsorship program for children from low-income families. Additionally, we are associated with music and entertainment through Devsuchi Creation Pvt. Ltd. We proudly introduced the album &quot;THE PEN AND DEVEN,&quot; which was recognized by various musical companies, with the best lyricist award presented by the President of Nepal. We look forward to serving you as both your host and friend in Nepal.</p>\r\n					<p class=\"font-italic mb-0\">\r\n						&quot;Your satisfaction is our greatest reward.&quot;</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</section>\r\n',	0,	'',	1,	'',	'',	'',	0,	'2025-11-26 10:51:59',	'2025-12-15 17:06:15',	6,	1,	'a:0:{}',	'',	'',	0,	''),
(32,	0,	'entertainment',	'Entertainment',	'Vibrant Nightlife & Fun ',	'<p>\r\n	&nbsp;</p>\r\n<p>\r\n	&nbsp;</p>\r\n<p>\r\n	aboutTitle: &quot;Lively. Dynamic. Unforgettable.&quot;, aboutSubtitle: &quot;Unforgettable Nights&quot;</p>\r\n<p>\r\n	Enjoy live music, performances, and a lively atmosphere every night. Our entertainment venues feature talented artists, themed events, and interactive experiences that keep guests engaged and entertained.&quot;, &quot;Our entertainment venues offer something for everyone, from karaoke to cultural shows. Whether you&rsquo;re looking to dance the night away or enjoy a quiet evening with friends, our hotel provides a vibrant social scene and unforgettable nights.</p>\r\n',	0,	'',	1,	'',	'',	'',	0,	'2025-12-12 16:59:57',	'2025-12-12 17:01:54',	1,	0,	'a:1:{i:0;s:11:\"tPwvY-5.jpg\";}',	'',	'',	0,	''),
(31,	0,	'investment',	'Investment',	'Business Opportunities',	'<p>\r\n	Discover exciting investment opportunities in Nepal&#39;s growing hospitality sector. Our projects are designed for sustainable growth, innovation, and long-term success, offering attractive returns for partners and stakeholders.&quot;, &quot;Partner with us to build a future of innovation and success. We provide comprehensive support, market insights, and strategic collaborations to help you achieve your business goals in the dynamic hospitality industry.</p>\r\n',	0,	'',	1,	'',	'',	'',	0,	'2025-12-12 16:28:01',	'2025-12-15 20:15:56',	2,	0,	'a:1:{i:0;s:11:\"8GHLu-8.jpg\";}',	'',	'',	0,	''),
(30,	0,	'hospitality',	'Hospitality',	'Training & Career Opportunities',	'Essential Hospitality Training Center delivers comprehensive education in both theoretical and practical aspects of the hospitality industry. We create pathways and opportunities for aspiring professionals passionate about building successful careers in hospitality.\",\r\n            \"Our diverse course offerings include culinary fundamentals with hands-on kitchen training, professional bartending, barista certification, bakery skills, service excellence, caregiver training, therapy, and more. With specialized training, students gain the confidence and expertise to excel in any challenging situation in this dynamic and global industry.',	0,	'',	1,	'',	'',	'',	0,	'2025-12-03 15:13:22',	'2025-12-12 16:55:35',	3,	0,	'a:1:{i:0;s:19:\"1AN20-essential.jpg\";}',	'',	'',	0,	'Empowering the next generation of hospitality professionals with world-class training and career-focused education.'),
(33,	0,	'coffee',	'Coffee',	'Specialty Coffee Blends',	'            aboutTitle: \"Aromatic. Smooth. Inviting.\",\r\n            aboutSubtitle: \"Aromatic Moments\"\r\n\r\nExperience the rich flavors of Nepalese coffee in our cozy cafés. Our inviting spaces are perfect for relaxing, meeting friends, or catching up on work, all while enjoying the aroma of freshly brewed coffee.\",\r\n                \"Our baristas craft each cup with care, using beans sourced from the Himalayas. Choose from a selection of specialty blends, pastries, and light bites. Whether you prefer a classic espresso or a creative latte, our café is your destination for aromatic moments and warm hospitality.',	0,	'',	1,	'',	'',	'',	0,	'2025-12-14 11:39:43',	'2025-12-14 11:39:43',	4,	0,	'a:1:{i:0;s:11:\"baZfo-9.jpg\";}',	'',	'',	0,	'Enjoy signature coffee blends crafted from the finest beans. Relax in a cozy café ambiance designed for comfort and connection.'),
(34,	0,	'wellness',	'Wellness',	'Relax & Rejuvenate',	'<p>\r\n	Unwind with our range of spa treatments and wellness therapies. Our expert therapists use natural products and traditional techniques to help you achieve deep relaxation and rejuvenation.&quot;, &quot;Our wellness center is designed to restore balance and vitality to your body and mind. Enjoy yoga sessions, meditation classes, and personalized wellness programs tailored to your needs. Escape the stresses of daily life and embrace a holistic approach to well-being.</p>\r\n',	0,	'',	1,	'',	'',	'',	0,	'2025-12-14 11:41:09',	'2025-12-15 17:21:34',	5,	0,	'a:1:{i:0;s:13:\"u2iaV-spa.jpg\";}',	'',	'',	0,	'');
INSERT INTO `tbl_blog` (`id`, `slug`, `title`, `author`, `brief`, `content`, `blog_date`, `archive_date`, `sortorder`, `status`, `image`, `source`, `type`, `viewcount`, `meta_keywords`, `meta_description`, `added_date`, `linksrc`, `linktype`, `upcoming`) VALUES
(2,	'top-fishing-destinations-in-nepal-you-cant-miss',	'Top Fishing Destinations in Nepal You Can\'t Miss',	'Himalayan Tighlines',	'Nepal is home to several spectacular rivers that offer incredible fishing opportunitiesAmong them, the Seti, Karnali, and Babai rivers\r\n',	'<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	Nepal is home to several spectacular rivers that offer incredible fishing opportunities. Among them, the Seti, Karnali, and Babai rivers stand out for their unique charm and abundant fish.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	1. Seti River: Flowing through the picturesque valleys of western Nepal, the Seti River is known for its clear waters and healthy populations of mahseer and trout. Its scenic gorges and gentle rapids make it a favorite spot for anglers seeking both adventure and tranquility.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	2. Karnali River: As one of Nepals largest and most biodiverse rivers, the Karnali offers an unparalleled fishing experience. Anglers can catch a variety of fish species, including the prized golden mahseer, while enjoying the untouched natural beauty of the surrounding landscapes.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	3. Babai River: Located in the midwestern region, the Babai River is a hidden gem for fishing enthusiasts. Its calm stretches and lush surroundings make it ideal for fly-fishing and family-friendly fishing trips, offering a peaceful retreat away from crowded tourist areas.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	Each of these rivers not only promises exciting fishing opportunities but also provides a chance to connect with Nepal rich natural heritage. Whether you are seeking adventure, tranquility, or both, Seti, Karnali, and Babai are must-visit destinations for every angler.</p>\r\n',	'2019-11-06',	'0000-00-00',	3,	1,	'0G0qt-01.jpg',	'',	0,	0,	'',	'',	'2025-11-26 11:11:57',	'http://www.',	'0',	0),
(3,	'sustainable-fishing-practices-in-nepal',	'Sustainable Fishing Practices in Nepal',	'Himalayan Tighlines',	'Fishing is not only a popular recreational activity in Nepal but also an important source of livelihood',	'<div class=\"blog-info\" style=\"box-sizing: inherit; color: rgb(117, 127, 149); font-family: Foregen, serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<div class=\"blog-details\" style=\"box-sizing: inherit; scroll-behavior: inherit !important;\">\r\n		<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; scroll-behavior: inherit !important;\">\r\n			Fishing is not only a popular recreational activity in Nepal but also an important source of livelihood for many communities. However, overfishing, pollution, and habitat degradation pose significant threats to the country&rsquo;s aquatic ecosystems. Adopting sustainable fishing practices is essential to ensure that Nepal&rsquo;s rivers and lakes remain healthy and productive for generations to come.</p>\r\n		<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; scroll-behavior: inherit !important;\">\r\n			Key Sustainable Fishing Practices in Nepal:</p>\r\n		<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; scroll-behavior: inherit !important;\">\r\n			Catch and Release: Encouraging anglers to release fish back into rivers and lakes helps maintain fish populations and preserves biodiversity. This practice is particularly important for endangered species like the golden mahseer.</p>\r\n		<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; scroll-behavior: inherit !important;\">\r\n			Regulated Fishing Seasons: Observing seasonal restrictions allows fish to breed and grow, preventing overfishing during critical spawning periods.</p>\r\n		<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; scroll-behavior: inherit !important;\">\r\n			Use of Eco-Friendly Gear: Avoiding harmful fishing methods such as chemical poisoning, dynamite, or gill nets helps protect aquatic habitats and non-target species.</p>\r\n		<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; scroll-behavior: inherit !important;\">\r\n			Waste Management: Proper disposal of fishing-related waste, including lines, hooks, and packaging, prevents pollution in rivers and lakes. Community Awareness: Educating local communities and anglers about sustainable practices fosters a culture of conservation and responsible fishing.</p>\r\n		<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; scroll-behavior: inherit !important;\">\r\n			By following these practices, both recreational and commercial fishers can contribute to preserving Nepal&rsquo;s rich aquatic biodiversity. Sustainable fishing not only ensures long-term fish availability but also protects the natural beauty and ecological balance of Nepal&rsquo;s rivers and lakes.</p>\r\n	</div>\r\n</div>\r\n<p>\r\n	&nbsp;</p>\r\n',	'2025-02-02',	'0000-00-00',	2,	1,	'xtosR-02.jpg',	'',	0,	0,	'',	'',	'2025-11-26 11:12:33',	'',	'0',	0),
(4,	'top-techniques-to-catch-more-fish-in-india',	'Top Techniques to Catch More Fish in India',	'Himalayan Tighlines',	'Fishing in India offers a diverse and exciting experience, thanks to its vast network of rivers, lakes, and coastal waters',	'<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	Fishing in India offers a diverse and exciting experience, thanks to its vast network of rivers, lakes, and coastal waters. Whether you are a beginner or an experienced angler, mastering the right techniques can significantly improve your catch. Here are some of the top techniques to help you catch more fish in India:</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	1. Know Your Waters &ndash; Understanding the behavior of fish in different environments is crucial. Rivers like the Ganga, Yamuna, and Godavari, as well as lakes such as Vembanad and Dal, host different species that require different approaches.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	2. Use the Right Bait &ndash; Different fish species respond to specific baits. For example, rohu and catla prefer live bait like worms or small insects, while carp and tilapia are attracted to dough balls or corn.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	3. Master Casting Techniques &ndash; Proper casting ensures that your bait reaches the ideal fishing spot. Practicing long casts, precise placement, and using the current effectively can make a huge difference.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	4. Choose the Appropriate Gear &ndash; Select rods, reels, and lines that match the type of fish and water body. Light tackle works well for smaller freshwater fish, while stronger rods and reels are essential for larger species like catfish or barramundi.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	5. Observe Seasonal Patterns &ndash; Fish activity changes with seasons. Monsoon and post-monsoon periods often yield better catches in rivers, while lakes may be more productive in cooler months.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	6. Practice Patience and Stealth &ndash; Fish are sensitive to noise and vibrations. Maintaining a calm presence and minimizing disturbances increases your chances of a successful catch.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	7. Try Fly Fishing and Surface Fishing &ndash; For rivers with fast-flowing water or trout-rich streams, fly fishing can be highly effective. Surface fishing, using floating baits, works well in calm lakes and ponds.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	By combining these techniques with local knowledge and a respect for the environment, anglers can significantly enhance their fishing experience in India. With patience, skill, and practice, every trip can become a rewarding adventure.</p>\r\n<p class=\"mb-10\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	&nbsp;</p>\r\n',	'2024-02-02',	'0000-00-00',	1,	1,	'RGz3U-03.jpg',	'',	0,	0,	'',	'',	'2025-11-26 11:12:54',	'',	'0',	0);
