INSERT INTO `tbl_faq` (`id`, `title`, `title_gr`, `content`, `content_gr`, `status`, `sortorder`, `added_date`) VALUES
(1,	' Target Species',	'',	'<ul style=\"box-sizing: inherit; padding-right: 0px; padding-left: 0px; margin: 0px; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Primary: Golden Mahseer, Goonch (Giant Catfish)</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Also Found: Raja Bam (Eel), Snow Trout, Katle</li>\r\n</ul>\r\n<p>\r\n	<span style=\"box-sizing: inherit; font-weight: bolder; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">NOTE: We strictly follow a Catch &amp; Release policy, especially for Golden Mahseer and Goonch.</span></p>\r\n',	'',	1,	3,	'2025-11-26 11:07:20'),
(2,	'Best Season',	'',	'<ul style=\"box-sizing: inherit; padding-right: 0px; padding-left: 0px; margin: 0px; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Prime fishing months: March-April and October-November.</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Trips are mainly floating expeditions combining day-time spinning/fly fishing and night-time bait fishing - camping wild along the riverbanks.</li>\r\n</ul>\r\n',	'',	1,	2,	'2025-11-26 11:07:32'),
(3,	' Packages & Pricing',	'',	'<p>\r\n	<span style=\"color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px;\">Detailed itineraries available upon request. Prices are customized and shared upon inquiry.</span></p>\r\n',	'',	1,	1,	'2025-11-26 11:07:42'),
(4,	' Lodging & Camping',	'',	'<p>\r\n	<span style=\"box-sizing: inherit; font-weight: bolder; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">During Our Floating Tripes, We Provide:</span></p>\r\n<ul style=\"box-sizing: inherit; padding-right: 0px; padding-left: 0px; margin: 0px; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Double yoga mattresses for comfort</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		All meals, tea, coffee, and cold drinks</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Evening campfire stories and fishing experiences</li>\r\n</ul>\r\n',	'',	1,	4,	'2025-11-27 16:53:42'),
(5,	' What To Bring',	'',	'<ul style=\"box-sizing: inherit; padding-right: 0px; padding-left: 0px; margin: 0px; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Personal Tackle</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Clothing Suitable For Fishing</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Headlamp</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Passport</li>\r\n</ul>\r\n',	'',	1,	5,	'2025-11-27 16:54:19');
