INSERT INTO `tbl_itinerary` (`id`, `package_id`, `title`, `day`, `slug`, `image`, `content`, `breakfast`, `lunch`, `dinner`, `hotel1`, `hotel2`, `hotel3`, `sortorder`, `status`) VALUES
(17,	20,	'6:00 AM – Wake Up / Light Breakfast',	'1',	'6-00-am-wake-up-light-breakfast',	'',	'<p>\r\n	Eat something light but energizing (oatmeal, banana, coffee) Hydrate</p>\r\n',	0,	0,	0,	'',	'',	'',	5,	1),
(18,	20,	'6:45 AM – Depart for Trailhead',	'2',	'6-45-am-depart-for-trailhead',	'',	'<p>\r\n	Double-check gear</p>\r\n<p>\r\n	Drive or walk to trailhead</p>\r\n',	0,	0,	0,	'',	'',	'',	7,	1),
(19,	20,	'7:30 AM – Begin Hike',	'3',	'7-30-am-begin-hike',	'',	'<p>\r\n	Warm-up, set a steady pace</p>\r\n<p>\r\n	Enjoy early light and cooler temps</p>\r\n',	0,	0,	0,	'',	'',	'',	1,	1),
(20,	20,	'9:00 AM – Short Break',	'4',	'9-00-am-short-break',	'',	'<p>\r\n	Hydrate, snack (trail mix, energy bar)</p>\r\n<p>\r\n	Check map and progress</p>\r\n',	0,	0,	0,	'',	'',	'',	3,	1),
(21,	20,	'11:00 AM – Reach Midpoint / Summit / Viewpoint',	'5',	'11-00-am-reach-midpoint-summit-viewpoint',	'',	'<p>\r\n	Enjoy the scenery</p>\r\n<p>\r\n	Take photos</p>\r\n<p>\r\n	Eat light lunch or extended snack.</p>\r\n',	0,	0,	0,	'',	'',	'',	8,	1),
(22,	20,	'1:00 AM – Short Break',	'6',	'1-00-am-short-break',	'',	'<p>\r\n	Hydrate, snack (trail mix, energy bar)</p>\r\n<p>\r\n	Check map and progress</p>\r\n',	0,	0,	0,	'',	'',	'',	10,	1),
(25,	4,	' Day 1 Arrive at Kathmandu Airport',	'1',	'day-1-arrive-at-kathmandu-airport',	'',	'<p>\r\n	<span style=\"color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px;\">Hotel Check In</span></p>\r\n',	0,	0,	0,	'',	'',	'',	2,	1),
(26,	4,	' Day 2 Early morning flight to Dhangadi (1 hour 15 mins)                                     ',	'2',	'day-2-early-morning-flight-to-dhangadi-1-hour-15-mins',	'',	'<ul style=\"box-sizing: inherit; padding-right: 0px; padding-left: 0px; margin: 0px; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Drive to Dipayal</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Arive at first camp</li>\r\n</ul>\r\n',	0,	0,	0,	'',	'',	'',	4,	1),
(27,	4,	' Day 3 to Day 10  Fishing through various locations                                     ',	'3',	'day-3-to-day-10-fishing-through-various-locations',	'',	'<p>\r\n	<span style=\"color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px;\">Camp will be shifted periodically</span></p>\r\n',	0,	0,	0,	'',	'',	'',	6,	1),
(28,	4,	' Day 11 End of fishing Trips                                     ',	'4',	'day-11-end-of-fishing-trips',	'',	'<ul style=\"box-sizing: inherit; padding-right: 0px; padding-left: 0px; margin: 0px; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Exit river by 2 PM</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Lunch Break</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Drive to Nepalgunj(2 hours)</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Flight from Nepalgunj to Kathmandu</li>\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Overnight stay at Kathmandu</li>\r\n</ul>\r\n',	0,	0,	0,	'',	'',	'',	9,	1),
(29,	4,	' Day 12 Departure from Kathamandu to respective destinations                                     ',	'5',	'day-12-departure-from-kathamandu-to-respective-destinations',	'',	'<ul style=\"box-sizing: inherit; padding-right: 0px; padding-left: 0px; margin: 0px; color: rgb(0, 0, 0); font-family: Lato, sans-serif; font-size: 16px; scroll-behavior: inherit !important;\">\r\n	<li style=\"box-sizing: inherit; scroll-behavior: inherit !important; list-style: none;\">\r\n		Airport drop and luggage assistance will be peovided during departure</li>\r\n</ul>\r\n',	0,	0,	0,	'',	'',	'',	11,	1);
