(5,	'deluxe-room',	'Deluxe Room',	'a:2:{i:0;s:16:\"sSSce-deluxe.jpg\";i:1;s:20:\"VzmZF-deluxe-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Relax in the sumptuous comfort of our Deluxe Room equipped with Luxury amenities, where every amenity is tailored for your blissful retreat.</p>\r\n',	'Hotel Manang',	'',	'',	'',	'',	1,	9,	'2025-12-12 20:10:39',	'2025-12-16 10:19:09',	3,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'https://www.hotelmanang.com/subpackage/deluxe-room',	'https://www.hotelmanang.com/result.php?hotel_code=CjvOin',	NULL,	'',	0),
(6,	'super-deluxe-room',	'Super Deluxe Room',	'a:2:{i:0;s:15:\"8kOlj-super.jpg\";i:1;s:18:\"FPjJg-supe-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Indulge in the unparalleled luxury of our Super Deluxe Room, a sanctuary of sophistication and comfort. Each rooms are elevator accessed and differently abled friendly.</p>\r\n',	'Hotel Manang',	'',	'',	'',	'',	1,	8,	'2025-12-13 21:51:12',	'2025-12-15 11:57:15',	3,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'2 Adults',	'',	'',	'',	'https://www.hotelmanang.com/subpackage/super-deluxe-room',	'https://www.hotelmanang.com/result.php?hotel_code=CjvOin',	NULL,	NULL,	NULL),
(7,	'inter-connected-room',	'Inter-Connected Room',	'a:2:{i:0;s:15:\"mP676-inter.jpg\";i:1;s:19:\"iS0yH-inter-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Our Interconnected Rooms offer the perfect blend of privacy and togetherness for families and groups.</p>\r\n',	'Hotel Manang',	'',	'',	'',	'',	1,	7,	'2025-12-13 22:15:08',	'2025-12-14 21:23:46',	3,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'3 Adults',	'',	'',	'',	'https://www.hotelmanang.com/subpackage/inter-connected-room',	'https://www.hotelmanang.com/result.php?hotel_code=CjvOin',	NULL,	NULL,	NULL),
(8,	'1-bhk',	'1 BHK',	'a:2:{i:0;s:11:\"Syl3q-1.jpg\";i:1;s:15:\"4bVrX-1-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Experience the perfect blend of comfort and functionality in our 1 BHK unit, thoughtfully designed with modern amenities, spacious interiors, and a cozy atmosphere to make you feel at home.</p>\r\n',	'Majestic Room & Apartment',	'',	'',	'',	'',	1,	5,	'2025-12-13 22:17:07',	'2025-12-14 21:22:39',	3,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'2 Adults',	'',	'',	'',	'contact-us',	'contact-us',	NULL,	NULL,	NULL),
(9,	'2-bhk',	'2 BHK',	'a:2:{i:0;s:11:\"S8mFz-2.jpg\";i:1;s:15:\"tGwGe-2-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Enjoy the spacious elegance of our 2 BHK unit, featuring well-designed interiors, modern amenities, and ample living space&mdash;perfect for families or those seeking extra comfort and convenience.</p>\r\n',	'Majestic Room & Apartment',	'',	'',	'',	'',	1,	3,	'2025-12-13 22:19:43',	'2025-12-14 21:22:50',	3,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'4 Adults',	'',	'',	'',	'contact-us',	'contact-us',	NULL,	NULL,	NULL),
(10,	'3-bhk',	'3 BHK',	'a:2:{i:0;s:15:\"yAcus-2-alt.jpg\";i:1;s:15:\"vk0bp-1-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Step into the luxury of our 3 BHK unit, offering expansive living spaces, elegant interiors, and premium amenities&mdash;ideal for larger families who value both comfort and style.</p>\r\n',	'Majestic Room & Apartment',	'',	'',	'',	'',	1,	1,	'2025-12-13 22:21:47',	'2025-12-14 21:23:01',	3,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'6 Adults',	'',	'',	'',	'contact-us',	'contact-us',	NULL,	NULL,	NULL),
(11,	'bhojghar',	'Bhojghar',	'a:2:{i:0;s:11:\"ghS64-1.jpg\";i:1;s:15:\"YBj47-1-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Located in unique blend of culture, adventure, and entertainment, making it a must-visit destination for travelers exploring Kathmandu, Bhojghar is known for its vibrant atmosphere and diverse offerings.</p>\r\n',	'',	'',	'',	'',	'',	1,	6,	'2025-12-14 11:59:15',	'2025-12-15 15:50:12',	4,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'images/download/docs/hFHN5-bhojgharflyer.pdf',	0),
(12,	'thamel-event',	'Thamel Event',	'a:2:{i:0;s:11:\"VCWlS-6.jpg\";i:1;s:15:\"zpjWn-2-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	Thamel Event &amp; Club stands as Kathmandu&#39;s premier destination for extraordinary occasions. Our exceptional venue comfortably welcomes 400-500 guests, perfectly accommodating everything from vibrant club experiences to professional seminars, elegant banquet functions, and sophisticated gala dinners.</p>\r\n',	'',	'',	'',	'',	'',	1,	4,	'2025-12-14 12:09:45',	'2025-12-15 16:04:57',	4,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	NULL,	'images/download/docs/H0ysl-main.pdf',	0),
(13,	'thamel-restaurant',	'Thamel Restaurant',	'a:2:{i:0;s:11:\"cjaA6-3.jpg\";i:1;s:15:\"Mebwr-3-alt.jpg\";}',	'a:0:{}',	'<p>\r\n	A pure veg and vegan restaurant, committed to serving healthy, wholesome, and delicious plant-based meals in a warm and welcoming environment. We take pride in promoting mindful eating and Nepalese hospitality at its finest, open daily from 7 A.M to 10 P.M.</p>\r\n',	'',	'',	'',	'',	'',	1,	2,	'2025-12-14 12:10:38',	'2025-12-16 10:47:09',	4,	'',	'',	0,	'',	'',	'',	'',	NULL,	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	'',	NULL,	'https://www.hotelmanang.com/page/dining',	1);
