(30,	'ayurspa',	'ayurSpa',	'Holistic Healing for Body, Mind & Spirit',	'a:1:{i:0;s:19:\"FLsQR-company11.png\";}',	'',	'',	0,	'<p>\r\n	Discover complete harmony at Ayur Wellness Spa &amp; Yoga, where ancient Ayurvedic wisdom meets modern relaxation. Our therapies and yoga practices restore balance, vitality, and inner peace. Step into a serene space designed to nurture your body, calm your mind, and uplift your spirit.</p>\r\n',	1,	'2025-12-11 19:00:59',	2,	0,	2,	'd',	0,	0,	0,	'a:1:{i:0;s:19:\"DUXWN-company11.jpg\";}',	'a:1:{i:0;s:13:\"kFiak-spa.jpg\";}',	'',	'images/download/docs/03zrQ-flyer.pdf',	0,	0,	'+977 9851126261',	'Chaksibari Marg, Kathmandu, Nepal',	'',	'https://www.facebook.com/ayurrwelness/',	'',	'',	'',	'',	''),
(31,	'essentialinstitute',	'essentialInstitute',	'Shaping Future Hospitality Leaders',	'a:1:{i:0;s:19:\"CckVV-company12.png\";}',	'',	'',	1,	'<p>\r\n	Specialized courses in bakery, barista skills, and caf&eacute; operations. The programs are designed to equip students with practical skills for careers in the hospitality industry.</p>\r\n',	1,	'2025-12-11 19:01:20',	1,	0,	2,	's',	0,	0,	0,	'a:1:{i:0;s:19:\"6P23D-company12.jpg\";}',	'a:1:{i:0;s:19:\"3SIzU-essential.jpg\";}',	'',	'https://www.facebook.com/dha.essentialnepal.fb/?locale=ne_NP',	0,	1,	' +977 1 5918239',	' Kathmandu, Nepal ',	'',	'https://www.facebook.com/dha.essentialnepal.fb/?locale=ne_NP',	'',	'',	'',	'',	''),
(28,	'yeticoffee',	'yetiCoffee',	'From the Peaks to Your Cup',	'a:1:{i:0;s:18:\"q38AZ-company9.png\";}',	'',	'',	0,	'<p>\r\n	Yeti Mountain Coffee is a specialty coffee brand that showcases the rich flavors of Nepal&rsquo;s high-altitude beans. Cultivated in pristine mountain environments, these beans are celebrated for their medium body, floral aroma, and subtle notes of citrus and spice.</p>\r\n',	1,	'2025-12-11 18:59:32',	4,	0,	2,	's',	0,	0,	0,	'a:1:{i:0;s:18:\"7FcC3-company9.jpg\";}',	'a:1:{i:0;s:11:\"IGu2a-9.jpg\";}',	'',	'images/download/docs/P4hIK-yeti.jpg',	0,	0,	'+977 1 4959999',	'Nayabazar, Kathmandu',	'',	'',	'',	'',	'',	'',	''),
