(24,	'yeticave',	'yetiCave',	'A Cave of Flavor, Fun & Song',	'a:1:{i:0;s:18:\"cFBkA-company5.png\";}',	'',	'',	0,	'<p>\r\n	Kathmandu&rsquo;s hotspot for great food, lively karaoke, and unforgettable nights with friends.</p>\r\n',	1,	'2025-12-11 17:19:47',	8,	0,	2,	'ds',	0,	0,	0,	'a:1:{i:0;s:18:\"DDHm0-company5.jpg\";}',	'a:1:{i:0;s:11:\"2ibnl-5.jpg\";}',	'',	'',	0,	0,	'+977 9709107441',	' Chaksibari Marg, Thamel, Kathmandu',	'',	'https://www.facebook.com/people/Yeti-Cave-Restaurant-Club-Karaoke/61571773282095/',	'',	'',	'',	'',	''),
