(27,	'devsuchi',	'devsuchi',	'Expressing Creativity',	'a:1:{i:0;s:18:\"RpMAV-company8.png\";}',	'',	'',	0,	'<p>\r\n	DHA is deeply entrenched in the realm of music and entertainment through Devsuchi Creation Pvt. Ltd. Our latest album, THE PEN AND DEVEN, has garnered widespread acclaim and prestigious recognition, including the esteemed Best Lyricist Award from the President.</p>\r\n',	1,	'2025-12-11 18:59:09',	5,	0,	2,	'erter',	0,	0,	0,	'a:1:{i:0;s:18:\"bBkON-company8.jpg\";}',	'a:1:{i:0;s:11:\"LxKSC-8.jpg\";}',	'',	'',	0,	0,	'+977 9851052685',	'Naikap, Kathmandu',	'',	'https://www.facebook.com/devsuchi.creation',	'',	'https://www.youtube.com/channel/UCV2RuqTlTcRiSVLV62ata9w',	'',	'',	''),
