(21,	'bhojghar',	'bhojghar',	'A House of Complete Hospitality',	'a:1:{i:0;s:18:\"qIh7A-company2.png\";}',	'',	'',	0,	'<p>\r\n	Experience the essence of traditional Nepalese culture while savoring authentic Nepali and Newari cuisine in a warm, homely atmosphere.</p>\r\n',	1,	'2025-12-11 17:18:21',	11,	0,	2,	'df',	0,	0,	0,	'a:1:{i:0;s:18:\"L21PE-company2.jpg\";}',	'a:1:{i:0;s:11:\"aA1uE-2.jpg\";}',	'',	'images/download/docs/hFHN5-bhojgharflyer.pdf',	0,	0,	'+977-9851126262',	'Thamel, Kathmandu, Nepal',	'',	'https://www.facebook.com/people/%E0%A4%A5%E0%A4%95%E0%A4%BE%E0%A4%B2%E0%A5%80-BhojGhar/100091471434366/',	'https://www.instagram.com/bhojgharrestaurantloungebar/',	'',	'https://x.com/bhojghar',	'',	''),
(22,	'majesticroomapartment',	'majesticRoomApartment',	'Luxury Living Within Your Reach',	'a:1:{i:0;s:18:\"cgkDj-company3.png\";}',	'',	'',	0,	'<p>\r\n	Majestic Apartment &amp; Hotel is an authentic and traditional apartment hotel in Kathmandu where budget rooms and meditation halls are available. The facilities are carefully designed for spiritual tourism puposes. That is why; it is one of the best residential place for tourists whose primary purpose is spirituality. Tourist can experience different kinds of Yoga and Meditation at this hotel.</p>\r\n',	1,	'2025-12-11 17:18:47',	10,	0,	2,	'dsf',	0,	0,	0,	'a:1:{i:0;s:18:\"t8UXc-company3.jpg\";}',	'a:1:{i:0;s:11:\"uoTrL-3.jpg\";}',	'',	'images/download/docs/hFHN5-bhojgharflyer.pdf',	0,	0,	' +977 9851126262',	'Nayabazar, Kathmandu',	'',	'',	'',	'',	'',	'',	'');
