INSERT INTO `tbl_testimonial` (`id`, `parentOf`, `name`, `image`, `linksrc`, `content`, `rating`, `sortorder`, `status`, `country`, `via_type`, `type`) VALUES
(1,	0,	' Rajesh P., Nepal',	'RsnpM-avatar.png',	'https://www.booking.com/',	'<div>\r\n	&nbsp;&quot;Absolutely incredible experience! The guides were professional and knew the rivers perfectly. I caught my first golden mahseer and it was unforgettable. Highly recommend Himalayan Tightlines for anyone serious about fishing.&quot;</div>\r\n<div>\r\n	&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</div>\r\n',	5,	1,	1,	'',	'Facebook',	0),
(2,	0,	'Priya R., UK',	'vOiZN-1.jpg',	'https://www.google.com/',	'<div>\r\n	&quot;The team was fantastic! They provided great tips, ensured safety, and made the entire experience fun and memorable. I can&rsquo;t wait to come back for another adventure with Himalayan Tightlines.&quot;</div>\r\n<div>\r\n	&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</div>\r\n',	3,	2,	1,	'',	'Google',	0),
(3,	0,	'Anjali S., India',	'ZMtVZ-avatar1.png',	'https://www.booking.com/',	'<div>\r\n	&quot;From booking to the actual trip, everything was seamless. The equipment was top-notch, meals were delicious, and the scenery was breathtaking. A true Himalayan fishing adventure!&quot;</div>\r\n<div>\r\n	&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</div>\r\n<div>\r\n	&nbsp;</div>\r\n',	5,	3,	1,	'',	'Customer',	0),
(4,	0,	'Michael T., USA',	'BBsNq-avatar.png',	'https://www.booking.com/',	'<div>\r\n	&quot;I&rsquo;ve fished all over the world, but Himalayan Tightlines offered something unique. The combination of pristine rivers, expert guides, and excellent hospitality made this trip truly special.&quot;</div>\r\n<div>\r\n	&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</div>\r\n',	5,	4,	1,	'',	'Facebook',	0);
